// packages/database/src/db/schema/dataset-search-query.ts
// Drizzle table: datasetSearchQuery (generated by scripts/split-schema.ts)

import {
  pgTable,
  index,
  text,
  timestamp,
  integer,
  jsonb,
  doublePrecision,
  type AnyPgColumn,
} from './_shared'
import { createId } from '@paralleldrive/cuid2'

import { Dataset } from './dataset'
import { Organization } from './organization'
import { User } from './user'

/** Drizzle table for datasetSearchQuery */
export const DatasetSearchQuery = pgTable(
  'DatasetSearchQuery',
  {
    id: text()
      .$defaultFn(() => createId())
      .primaryKey()
      .notNull(),
    query: text().notNull(),
    queryType: text().default('hybrid').notNull(),
    resultsCount: integer().default(0).notNull(),
    vectorSimilarityThreshold: doublePrecision().default(0.7),
    maxResults: integer().default(10).notNull(),
    filters: jsonb(),
    responseTime: integer().notNull(),
    createdAt: timestamp({ precision: 3 }).defaultNow().notNull(),
    datasetId: text()
      .notNull()
      .references((): AnyPgColumn => Dataset.id, { onUpdate: 'cascade', onDelete: 'cascade' }),
    organizationId: text()
      .notNull()
      .references((): AnyPgColumn => Organization.id, { onUpdate: 'cascade', onDelete: 'cascade' }),
    userId: text()
      .notNull()
      .references((): AnyPgColumn => User.id, { onUpdate: 'cascade', onDelete: 'cascade' }),
  },
  (table) => [
    index('DatasetSearchQuery_createdAt_idx').using('btree', table.createdAt.asc().nullsLast()),
    index('DatasetSearchQuery_datasetId_idx').using('btree', table.datasetId.asc().nullsLast()),
    index('DatasetSearchQuery_organizationId_idx').using(
      'btree',
      table.organizationId.asc().nullsLast()
    ),
    index('DatasetSearchQuery_userId_idx').using('btree', table.userId.asc().nullsLast()),
  ]
)
